  ('pukao-0a2fc18c-moex-00224', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '有關通貨膨脹的成本（costsofinflation），下列敘述何者錯誤？', '["未料到通貨膨脹（unanticipatedinflation）的代價之一是財富會出現重分配（redistributionofwealth）", "對於消費或生產決策，通貨膨脹會使得價格所提供的訊號參考價值降低", "貨幣的購買力（purchasingpower）會下降", "通貨膨脹稅（inflationtax）使得財政收入增加，健全了財稅制度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00225', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '下列何者不包括在「薪資所得」定義中？', '["教育補助費", "代表公司推廣業務之佣金", "車馬費", "自力耕作、漁、牧、林、礦之所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00226', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '內生成長模型（endogenousgrowthmodel）指出，研究與發展（researchanddevelopment）與創新（innovation） 是驅動每人所得（percapitaincome）永續增長的因素之一，而熊彼特（Schumpeter）的「創造性破壞（creative destruction）」理論則說明：', '["既有生產者（incumbentproducers）透過創新方法，以破壞經濟秩序來獲取利益，造成經濟進步", "新產品生產者（newproductproducers）藉由創新新產品，將既有生產者（incumbentproducers）驅離產 業，並驅動經濟進步", "既有生產者（incumbentproducers）破壞貿易壁壘（tradebarrier），以創造新利潤，驅動經濟進步", "新產品生產者（newproductproducers）開發天然資源，獲取利益並驅動經濟進步"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00227', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '景氣循環（businesscycles）的特徵之中，不會有下列何者？', '["歷經一段擴張期（expansionperiod）後，接著是一段收縮期（contractionperiod）", "許多經濟變數呈現共移性（comovement）現象", "擴張期間，實質利率（realinterestrate）上漲；而收縮期間，實質利率呈現下跌", "會反覆發生（recurrent），但週期並無規律性（nonperiodical）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00228', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '有關經濟成長（economicgrowth）的敘述，下列何者錯誤？', '["經濟成長之時，生產可能曲線（productionpossibilitycurve）呈現出向外擴張", "經濟成長狀態下，實質國內生產毛額（realGDP）呈現出上升趨勢", "一個每年平均經濟成長率為6%、每年平均每人實質GDP為3萬美元的國家，大約要24年的時間，其 每年平均每人實質GDP才會達到6萬美元", "由於名目國內生產毛額（nominal GDP）易受物價水準影響，所以不適宜使用名目國內生產毛額來比較 國家之間的經濟成長高低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
